+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(schema: TWrapped): RecursiveSchema<TWrapped> {
+  const recursiveSchema: RecursiveSchema<TWrapped> = {
+    kind: 'schema',
+    type: 'recursive',
+    reference: recursive,
+    expects: schema.expects,
+    async: false,
+    wrapped: schema,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset, config) {
+      return this.wrapped['~run'](dataset, config);
+    },
+  } as RecursiveSchema<TWrapped>;
+  (recursiveSchema as { wrapped: TWrapped }).wrapped = _replaceRecur(
+    schema,
+    recursiveSchema
+  );
+  return recursiveSchema;
+}
+
+/**
+ * Replaces recursive placeholders in a schema value.
+ *
+ * @internal
+ */
+export function _replaceRecur<TValue>(
+  value: TValue,
+  recursiveSchema: BaseSchema<unknown, unknown, BaseIssue<unknown>> | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
+  references = new Map<object, unknown>()
+): TValue {
+  if (value === Recur) {
+    return recursiveSchema as TValue;
+  }
+  if (!value || typeof value !== 'object') {
+    return value;
+  }
+  const cached = references.get(value);
+  if (cached) {
+    return cached as TValue;
+  }
+  if (value instanceof Map || value instanceof Set || value instanceof Date) {
+    return value;
+  }
+  const clone: Record<PropertyKey, unknown> | unknown[] = Array.isArray(value)
+    ? []
+    : Object.create(Object.getPrototypeOf(value));
+  references.set(value, clone);
+  for (const key of Reflect.ownKeys(value)) {
+    const descriptor = Object.getOwnPropertyDescriptor(value, key)!;
+    if ('value' in descriptor) {
+      descriptor.value = _replaceRecur(descriptor.value, recursiveSchema, references);
+    }
+    Object.defineProperty(clone, key, descriptor);
+  }
+  return clone as TValue;
+}
